CREATE OR REPLACE FUNCTION public.record_farm_production(p_date DATE,p_qty NUMERIC,p_transfer_price NUMERIC,p_population INTEGER,p_productive_count INTEGER,p_culled_count INTEGER,p_mortality INTEGER,p_feed_qty NUMERIC,p_feed_cost NUMERIC,p_notes TEXT DEFAULT NULL)
RETURNS SETOF public.farm_production LANGUAGE plpgsql SECURITY INVOKER SET search_path=public AS $$
DECLARE v_user UUID:=auth.uid();v_stock public.stock_states%ROWTYPE;v_record public.farm_production%ROWTYPE;v_cost NUMERIC;v_new_qty NUMERIC;v_new_avg NUMERIC;
BEGIN IF v_user IS NULL THEN RAISE EXCEPTION USING ERRCODE='42501',MESSAGE='Authentication required';END IF;IF p_qty<=0 OR p_transfer_price<=0 OR p_population<=0 OR p_productive_count<0 OR p_productive_count>p_population OR LEAST(p_culled_count,p_mortality,p_feed_qty,p_feed_cost)<0 THEN RAISE EXCEPTION 'Invalid farm production values';END IF;
INSERT INTO public.stock_states(id,qty,avg_cost,created_by,updated_by)VALUES('raw',0,0,v_user::text,v_user::text)ON CONFLICT(id)DO NOTHING;SELECT * INTO STRICT v_stock FROM public.stock_states WHERE id='raw' FOR UPDATE;v_cost:=p_qty*p_transfer_price;v_new_qty:=v_stock.qty+p_qty;v_new_avg:=((v_stock.qty*v_stock.avg_cost)+v_cost)/v_new_qty;
INSERT INTO public.farm_production(id,date,qty,transfer_price,population,productive_count,culled_count,mortality,feed_qty,feed_cost,notes,created_by,updated_by)VALUES('farm-'||gen_random_uuid()::text,p_date,p_qty,p_transfer_price,p_population,p_productive_count,p_culled_count,p_mortality,p_feed_qty,p_feed_cost,p_notes,v_user::text,v_user::text)RETURNING * INTO v_record;UPDATE public.stock_states SET qty=v_new_qty,avg_cost=v_new_avg,updated_by=v_user::text WHERE id='raw';INSERT INTO public.raw_transactions(id,date,type,qty,price_per_unit,total_cost,after_qty,after_avg_cost,ref_id,notes,created_by,updated_by)VALUES('raw-'||gen_random_uuid()::text,p_date,'PRODUCTION',p_qty,p_transfer_price,v_cost,v_new_qty,v_new_avg,v_record.id,'Farm production '||v_record.id,v_user::text,v_user::text);RETURN NEXT v_record;END;$$;
REVOKE ALL ON FUNCTION public.record_farm_production(DATE,NUMERIC,NUMERIC,INTEGER,INTEGER,INTEGER,INTEGER,NUMERIC,NUMERIC,TEXT)FROM PUBLIC;GRANT EXECUTE ON FUNCTION public.record_farm_production(DATE,NUMERIC,NUMERIC,INTEGER,INTEGER,INTEGER,INTEGER,NUMERIC,NUMERIC,TEXT)TO authenticated;
